// Level + Rangsystem laut CLAUDE.md §8.
//
// XP-Kurve: xp_for_level(L) = 100 * L * (L + 1) / 2
//   L=1 → 100, L=2 → 300, L=3 → 600, L=10 → 5500, L=50 → 127500
//
// Rang ergibt sich aus dem Level via RANK_TABLE.

export function xpForLevel(level: number): number {
  return 100 * level * (level + 1) / 2
}

/** Berechnet das aktuelle Level basierend auf Total-XP. Level 1 startet bei 0 XP. */
export function levelFromXp(xp: number): number {
  let level = 1
  while (xpForLevel(level) <= xp) level += 1
  return level
}

/** XP-Threshold für das nächste Level + Progress-Anteil [0..1]. */
export function progressInLevel(xp: number): { level: number; xpInto: number; xpToNext: number; pct: number } {
  const level = levelFromXp(xp)
  const xpStart = xpForLevel(level - 1)
  const xpEnd = xpForLevel(level)
  const xpInto = xp - xpStart
  const xpToNext = xpEnd - xpStart
  return {
    level,
    xpInto,
    xpToNext,
    pct: Math.min(1, Math.max(0, xpInto / xpToNext))
  }
}

// Rang-Tabelle (CLAUDE.md §8). HU-Form ist primary.
export const RANK_TABLE: Array<{ minLevel: number; rankHu: string; rankDe: string }> = [
  { minLevel: 1,   rankHu: 'Medikus I',   rankDe: 'Studi 1. Sem' },
  { minLevel: 5,   rankHu: 'Medikus II',  rankDe: 'Studi Vorklinik' },
  { minLevel: 10,  rankHu: 'Medikus III', rankDe: 'Studi Klinik' },
  { minLevel: 15,  rankHu: 'Gyakornok',   rankDe: 'Praktikant' },
  { minLevel: 20,  rankHu: 'Asszisztens', rankDe: 'Assistent' },
  { minLevel: 30,  rankHu: 'Rezidens',    rankDe: 'Assistenzarzt' },
  { minLevel: 45,  rankHu: 'Szakorvos',   rankDe: 'Facharzt' },
  { minLevel: 60,  rankHu: 'Adjunktus',   rankDe: 'Oberarzt' },
  { minLevel: 80,  rankHu: 'Főorvos',     rankDe: 'Chefarzt' },
  { minLevel: 100, rankHu: 'Professzor',  rankDe: 'Professor' }
]

export function rankFromLevel(level: number): { rankHu: string; rankDe: string } {
  let cur = RANK_TABLE[0]
  for (const r of RANK_TABLE) {
    if (level >= r.minLevel) cur = r
    else break
  }
  return cur
}
